mapper.select:
/* daily3gSubMapper.getDaily3gSubListExcel */ SELECT STDR_DT , CONTRACT_NUM , DECODE(REQ_BUY_TYPE,'UU','유심구매','MM','단말구매','') AS REQ_BUY_TYPE , LST_COM_ACTV_DATE , BIRTH_DT , GENDER , FN_GET_CODENM('RCP0037', SUB_STATUS) AS SUB_STATUS , OPEN_AGNT_CD , OPEN_AGNT_NM , LST_RATE_CD , LST_RATE_NM , FN_GET_CODENM('CMN0266', LST_RATE_TP) AS LST_RATE_TP , LST_MODEL_ID , LST_MODEL_NM , FN_GET_CODENM('CMN0266', LST_MODEL_TP) AS LST_MODEL_TP , MODEL_VOLTE_YN , MODEL_NFC_YN , LST_USIM_ID , LST_USIM_NM , FN_GET_CODENM('CMN0266', LST_USIM_TP) AS LST_USIM_TP , USIM_VOLTE_YN , USIM_NFC_YN , FN_GET_CODENM('CMN0058', BL_DC_TYPE) AS BL_DC_TYPE , ARGM_STRT_DT , ARGM_END_DT , STOP_DT , FN_GET_CODENM('MSP0004', STOP_RSN_CD) AS STOP_RSN_NM , FN_GET_CODENM('RCP0036', BILL_SEND_CD) AS BILL_SEND_NM FROM MSP_DAILY_3G_SUB WHERE STDR_DT = #{stdrDt}
AND SUB_STATUS = #{subStatus}
AND CONTRACT_NUM = #{searchVal}
AND LST_MODEL_ID IS NULL
AND LST_MODEL_TP = #{lstModelTp}
AND LST_RATE_TP = #{lstRateTp}
AND LST_USIM_TP = #{lstUsimTp}
AND MODEL_VOLTE_YN = #{volteYn}
ORDER BY LST_COM_ACTV_DATE DESC
